import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"220. Uniforms And Protective Clothing","description":"","frontmatter":{"title":"220. Uniforms And Protective Clothing","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/resources/220-uniforms-and-protective-clothing.md","filePath":"ebas/mental-health/management-admin/resources/220-uniforms-and-protective-clothing.md"}'),a={name:"ebas/mental-health/management-admin/resources/220-uniforms-and-protective-clothing.md"};function i(s,e,l,c,p,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_220-uniforms-and-protective-clothing" tabindex="-1">220. Uniforms And Protective Clothing <a class="header-anchor" href="#_220-uniforms-and-protective-clothing" aria-label="Permalink to &quot;220. Uniforms And Protective Clothing&quot;">​</a></h1><p><strong>220.1</strong> Where an Employee is required to wear a uniform or any special clothing, the Employer will supply such uniform at no cost to the Employee and will replace it where necessary on a fair ‘wear and tear’ basis.</p><p><strong>220.2</strong> Uniforms and special clothing provided in accordance with clause 220.1 and clause 220.3 shall remain the property of the Employer.</p><p><strong>220.3</strong> The Employer shall provide such gloves, masks, protective clothing and safety appliances as are required for an Employee to properly and safely perform their job function. Where the Employee is required to purchase such clothing and equipment, they shall be reimbursed in full by the Employer.</p><p><strong>220.4</strong> The rounding provision does not apply to the calculation of this allowance.</p>',5)])])}const u=t(a,[["render",i]]);export{d as __pageData,u as default};
